 function logAuthFailure(
   request: Request,
   reason: AuthenticateRequestFailureReason,
   diagnostics: { errorCode?: string; providerStatus?: number } = {},
 ): void {
   const url = new URL(request.url);

   console.warn("OIDC authentication failed", {
     path: url.pathname,
